package com.example.mpos.employee;
import android.database.Cursor;import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.auth.PermissionHelper;import com.example.mpos.database.DatabaseHelper;import java.util.*;
public class AuditLogActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);if(!PermissionHelper.requireAdmin(this))return;setContentView(R.layout.activity_audit_log);Cursor c=new DatabaseHelper(this).getReadableDatabase().rawQuery("SELECT action,entity_type,entity_id,detail FROM audit_logs ORDER BY created_at DESC LIMIT 100",null);List<String>rows=new ArrayList<>();try{while(c.moveToNext())rows.add(c.getString(0)+" • "+c.getString(1)+" #"+c.getLong(2)+(c.getString(3)==null?"":"\n"+c.getString(3)));}finally{c.close();}if(rows.isEmpty())rows.add("Chưa có nhật ký hoạt động");((ListView)findViewById(R.id.listAuditLogs)).setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_list_item_1,rows));findViewById(R.id.btnBack).setOnClickListener(v->finish());}}
